-- C0679 · Deadlock/locking demo (2 sesiones) (Avanzado, Base de datos)
-- Ejecutar en 2 sesiones (InnoDB).
-- Pre:
-- CREATE TABLE IF NOT EXISTS demo_lock(id int primary key, val int) ENGINE=InnoDB;
-- INSERT IGNORE INTO demo_lock(id,val) VALUES (1,10),(2,20);

-- SESIÓN A
START TRANSACTION;
  UPDATE demo_lock SET val = val + 1 WHERE id = 1;
  DO SLEEP(3);
  UPDATE demo_lock SET val = val + 1 WHERE id = 2;
COMMIT;

-- SESIÓN B
START TRANSACTION;
  UPDATE demo_lock SET val = val + 1 WHERE id = 2;
  DO SLEEP(3);
  UPDATE demo_lock SET val = val + 1 WHERE id = 1;
COMMIT;

